const users = $input.all().map(item => item.json);
const weekRange = $('Compute Week Range').first().json;
const userList = [
  { user_id: "00000000-0000-0000-0000-000000000000", is_generic: true },
  ...users.map(u => ({ user_id: u.user_id, is_generic: false }))
];
return userList.map(u => ({ json: { ...u, ...weekRange } }));

const input = $input.first().json;
const loopData = $('Loop Through Users').first().json;
if (loopData.is_generic) {
  return [{ json: {
    user_id: null,
    company_name: null,
    company_domain: null,
    competitor_ids: [],
    competitor_names: [],
    competitor_domains: [],
    user_industry: null,
    is_personalized: false,
    week_start: loopData.week_start,
    week_end: loopData.week_end
  }}];
}
return [{ json: {
  user_id: loopData.user_id,
  company_name: input.company_name || null,
  company_domain: input.company_domain || null,
  competitor_ids: input.competitor_ids || [],
  competitor_names: input.competitor_names || [],
  competitor_domains: input.competitor_domains || [],
  user_industry: input.user_industry || null,
  is_personalized: !!(input.company_name),
  week_start: loopData.week_start,
  week_end: loopData.week_end
}}];

const signals = $input.all().map(item => item.json);
const userContext = $('Format User Context').first().json;
const weekRange = { week_start: userContext.week_start, week_end: userContext.week_end };

const SHIP_CAPS = {
  messaging: 8, narrative: 5, icp: 5, horizon: 3, objection: 5,
  pricing: 4, proof: 3, distribution: 3, hiring: 2, launch_decay: 2, experiment: 5
};
const MAX_TOTAL = 45;
const WEIGHTS = { severity: 8, recency: 30, confidence: 15, source_quality: 15 };

function filterByUserCompetitors(allSignals, ctx) {
  if (!ctx || !ctx.competitor_ids || ctx.competitor_ids.length === 0) return allSignals;
  const competitorIds = new Set(ctx.competitor_ids);
  const competitorDomains = new Set((ctx.competitor_domains || []).map(d => d?.toLowerCase()));
  const competitorNames = new Set((ctx.competitor_names || []).map(n => n?.toLowerCase()));
  return allSignals.filter(signal => {
    if (signal.company_id && competitorIds.has(signal.company_id)) return true;
    for (const url of (signal.evidence_urls || [])) {
      const urlLower = (url || '').toLowerCase();
      for (const domain of competitorDomains) { if (domain && urlLower.includes(domain)) return true; }
    }
    const titleLower = (signal.title || '').toLowerCase();
    const summaryLower = (signal.summary || '').toLowerCase();
    for (const name of competitorNames) {
      if (name && (titleLower.includes(name) || summaryLower.includes(name))) return true;
    }
    return false;
  });
}

const filteredSignals = filterByUserCompetitors(signals, userContext);
let relevantSignals = [...filteredSignals];

// Auto-widening tiers
if (relevantSignals.length < 10 && userContext.user_industry) {
  const industrySignals = signals.filter(s => {
    if (relevantSignals.includes(s)) return false;
    return (s.meta || {}).industry === userContext.user_industry;
  });
  industrySignals.forEach(s => { s._widened = 'industry'; });
  relevantSignals = [...relevantSignals, ...industrySignals];
}
if (relevantSignals.length < 10) {
  const horizonSignals = signals.filter(s => !relevantSignals.includes(s) && s.signal_type === 'horizon');
  horizonSignals.forEach(s => { s._widened = 'horizon'; });
  relevantSignals = [...relevantSignals, ...horizonSignals];
}
if (relevantSignals.length < 5) {
  const highSeverity = signals.filter(s => !relevantSignals.includes(s) && (s.severity || 0) >= 4);
  highSeverity.forEach(s => { s._widened = 'market'; });
  relevantSignals = [...relevantSignals, ...highSeverity];
}

function computeScore(signal) {
  const now = new Date();
  const daysOld = (now - new Date(signal.created_at)) / (1000 * 60 * 60 * 24);
  const severityScore = (signal.severity || 3) * WEIGHTS.severity;
  const recencyScore = Math.max(0, WEIGHTS.recency - (daysOld * 4.3));
  const confidenceScore = (parseFloat(signal.confidence) || 0.5) * WEIGHTS.confidence;
  const sq = signal.source_quality || 'medium';
  const sourceScore = sq === 'high' ? 15 : sq === 'medium' ? 10 : 5;
  return Math.round((severityScore + recencyScore + confidenceScore + sourceScore) * 100) / 100;
}

const enriched = relevantSignals.map(s => ({ ...s, score: computeScore(s) }));

const sectionNames = ['messaging','narrative','icp','horizon','objection','pricing','proof','distribution','hiring','launch_decay','experiment'];
const selectedBySection = {};
let totalSelected = [];
for (const sec of sectionNames) {
  const cap = SHIP_CAPS[sec] || 6;
  const secSignals = enriched.filter(s => s.signal_type === sec).sort((a,b) => b.score - a.score).slice(0, cap);
  selectedBySection[sec] = secSignals;
  totalSelected = totalSelected.concat(secSignals);
}
if (totalSelected.length > MAX_TOTAL) {
  totalSelected.sort((a,b) => b.score - a.score);
  totalSelected = totalSelected.slice(0, MAX_TOTAL);
}

// Build STRUCTURED signal input — full data for each signal
const structuredSignals = totalSelected.map(s => ({
  signal_id: s.id,
  signal_type: s.signal_type,
  severity: s.severity,
  confidence: s.confidence,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || [],
  source_schema: s.source_schema,
  detected_at: s.created_at,
  widened_from: s._widened || null
}));

const isPersonalized = userContext.is_personalized;
const companyName = userContext.company_name || 'your company';
const competitorsList = (userContext.competitor_names || []).join(', ') || 'competitors';

// ====== ANTI-HALLUCINATION PROMPT ======
const systemPrompt = `You are a SIGNAL FORMATTER for a competitive intelligence system. You are NOT an analyst. You do NOT generate insights.

ABSOLUTE RULES — VIOLATION OF ANY RULE INVALIDATES THE ENTIRE OUTPUT:
1. You MUST ONLY report information that is EXPLICITLY present in the signals provided below.
2. Every statement you write MUST include a "signal_ids" array citing the specific signal(s) that support it.
3. If you CANNOT cite a signal_id for a statement, you MUST NOT include that statement.
4. You MUST NOT infer, speculate, predict, or extrapolate beyond what the signals explicitly state.
5. You MUST NOT fabricate competitor names, pricing, features, product launches, hires, or events.
6. You MUST NOT add context, background, or market knowledge that is not in the signals.
7. If a section has no relevant signals, return empty arrays for that section. Do NOT fill it with invented content.
8. Use the EXACT language from signals where possible. Paraphrase minimally.
9. For widened signals (industry/horizon/market), prefix with the context tag provided.

${isPersonalized ? `COMPANY: ${companyName}\nTRACKED COMPETITORS: ${competitorsList}\nFrame observations as "${companyName} vs [Competitor]" where relevant, but ONLY based on signal data.` : ''}

OUTPUT FORMAT — Strict JSON:
{
  "packet_title": "Week of YYYY-MM-DD: [brief factual title based on signals]",
  "exec_summary": [
    { "text": "string — one observation", "signal_ids": ["uuid"] }
  ],
  "sections": {
    "messaging": {
      "summary": "string — factual summary of messaging signals only",
      "highlights": [
        { "text": "string — one observed change", "signal_ids": ["uuid"] }
      ],
      "action_items": [
        { "text": "string — recommended action based on observed signal", "signal_ids": ["uuid"] }
      ]
    },
    "narrative": { "summary": "...", "highlights": [...], "action_items": [...] },
    "icp": { "summary": "...", "highlights": [...], "action_items": [...] },
    "horizon": { "summary": "...", "highlights": [...], "action_items": [...] },
    "objection": { "summary": "...", "highlights": [...], "action_items": [...] }
  },
  "key_questions": [
    { "text": "string — question raised by the signals", "signal_ids": ["uuid"] }
  ],
  "action_mapping": {
    "this_week": [{ "action": "str", "owner": "str", "priority": "str", "signal_ids": ["uuid"] }],
    "monitor": [{ "signal": "str", "trigger": "str", "action": "str", "signal_ids": ["uuid"] }]
  }
}

CRITICAL: Do NOT include "bets" or "predictions" sections. Only report what was observed.
If there are fewer than 3 signals for a section, it is BETTER to return fewer highlights than to invent content.`;

const userContent = `Week: ${weekRange.week_start} to ${weekRange.week_end}
${isPersonalized ? 'Company: ' + companyName : ''}
Total signals available: ${signals.length}
Signals selected for this packet: ${totalSelected.length}

SIGNALS (structured input — use signal_id to cite every claim):
${JSON.stringify(structuredSignals, null, 2)}

Organize and summarize ONLY the signals above. Do not add any information not present in the signals.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4000,
  temperature: 0.1,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

// Build signal ID set for validation
const validSignalIds = totalSelected.map(s => s.id);

return [{ json: {
  week_start: weekRange.week_start,
  week_end: weekRange.week_end,
  user_id: userContext.user_id,
  user_company_name: userContext.company_name,
  is_personalized: isPersonalized,
  competitor_names: userContext.competitor_names || [],
  total_signals: signals.length,
  filtered_signals: filteredSignals.length,
  selected_count: totalSelected.length,
  selected_signals: totalSelected,
  valid_signal_ids: validSignalIds,
  structured_signals: structuredSignals,
  anthropic_body: anthropicBody
}}];

const resp = $input.first().json;
const selectData = $('Score + Select Top Signals').first().json;
const validIds = new Set(selectData.valid_signal_ids || []);

let packetData;
try {
  const content = resp.content?.[0]?.text || '{}';
  const cleaned = content.replace(/^```json?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
  packetData = JSON.parse(cleaned);
} catch (e) {
  packetData = {
    packet_title: `Week of ${selectData.week_start}: Intelligence Packet (parse error)`,
    exec_summary: [],
    sections: { messaging: { summary: '', highlights: [], action_items: [] }, narrative: { summary: '', highlights: [], action_items: [] }, icp: { summary: '', highlights: [], action_items: [] }, horizon: { summary: '', highlights: [], action_items: [] }, objection: { summary: '', highlights: [], action_items: [] } },
    key_questions: [],
    action_mapping: { this_week: [], monitor: [] }
  };
}

// ====== VALIDATION: Strip uncited and invalid-cited claims ======
const auditTrail = [];
const validationErrors = [];

function validateCitedItems(items, location) {
  if (!Array.isArray(items)) return [];
  return items.filter(item => {
    const text = typeof item === 'string' ? item : (item.text || item.action || item.signal || '');
    const sids = item.signal_ids || [];

    // If item is a plain string (old format), flag but keep with warning
    if (typeof item === 'string') {
      validationErrors.push({ type: 'uncited_string', location, text: item });
      return false; // Strip uncited string claims
    }

    // Must have at least one signal_id
    if (!sids || sids.length === 0) {
      validationErrors.push({ type: 'no_citation', location, text });
      return false;
    }

    // Validate signal_ids exist in our input set
    const validSids = sids.filter(sid => validIds.has(sid));
    if (validSids.length === 0) {
      validationErrors.push({ type: 'invalid_citations', location, text, cited: sids });
      return false;
    }

    // Keep item, record in audit trail
    item.signal_ids = validSids; // Only keep valid signal_ids
    auditTrail.push({ claim_text: text, claim_location: location, signal_ids: validSids });
    return true;
  });
}

// Validate exec_summary
if (packetData.exec_summary) {
  packetData.exec_summary = validateCitedItems(packetData.exec_summary, 'exec_summary');
}

// Validate sections
const sectionNames = ['messaging', 'narrative', 'icp', 'horizon', 'objection'];
for (const sec of sectionNames) {
  const section = packetData.sections?.[sec];
  if (!section) continue;

  if (section.highlights) {
    section.highlights = validateCitedItems(section.highlights, `${sec}.highlights`);
  }
  if (section.action_items) {
    section.action_items = validateCitedItems(section.action_items, `${sec}.action_items`);
  }
}

// Validate key_questions
if (packetData.key_questions) {
  packetData.key_questions = validateCitedItems(packetData.key_questions, 'key_questions');
}

// Validate action_mapping
if (packetData.action_mapping) {
  if (packetData.action_mapping.this_week) {
    packetData.action_mapping.this_week = validateCitedItems(packetData.action_mapping.this_week, 'action_mapping.this_week');
  }
  if (packetData.action_mapping.monitor) {
    packetData.action_mapping.monitor = validateCitedItems(packetData.action_mapping.monitor, 'action_mapping.monitor');
  }
}

// Strip predictions and bets entirely (speculative features)
delete packetData.predictions;
delete packetData.bets;

// Convert cited exec_summary items to plain text array for DB storage
// but keep signal_ids in a separate field for the audit trail
const execSummaryTexts = (packetData.exec_summary || []).map(item => 
  typeof item === 'string' ? item : (item.text || '')
);

// Convert sections highlights/action_items to plain text arrays
for (const sec of sectionNames) {
  const section = packetData.sections?.[sec];
  if (!section) continue;
  section.highlights = (section.highlights || []).map(h => typeof h === 'string' ? h : (h.text || ''));
  section.action_items = (section.action_items || []).map(a => typeof a === 'string' ? a : (a.text || ''));
}

// Convert key_questions to plain text
const keyQuestionsTexts = (packetData.key_questions || []).map(q =>
  typeof q === 'string' ? q : (q.text || '')
);

// Store the validation metadata
const validationSummary = {
  total_claims: auditTrail.length + validationErrors.length,
  verified_claims: auditTrail.length,
  stripped_claims: validationErrors.length,
  errors: validationErrors
};

return [{ json: {
  ...selectData,
  packet: {
    ...packetData,
    exec_summary: execSummaryTexts,
    key_questions: keyQuestionsTexts,
    bets: [],
    predictions: []
  },
  audit_trail: auditTrail,
  validation_summary: validationSummary
}}];

const weekRange = $('Format User Context').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;
const userCtx = $('Format User Context').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;
const isPersonalized = userCtx.is_personalized;
const companyName = userCtx.company_name || 'your company';

const signals = scoreResult.selected_signals.filter(s =>
  ['messaging', 'narrative', 'icp', 'objection'].includes(s.signal_type)
);

const structuredSignals = signals.map(s => ({
  signal_id: s.id,
  signal_type: s.signal_type,
  severity: s.severity,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || []
}));

const systemPrompt = `You are a SIGNAL FORMATTER extracting objections from competitive intelligence signals${isPersonalized ? ` for ${companyName}` : ''}.

ABSOLUTE RULES:
1. ONLY extract objections that are EXPLICITLY mentioned or directly implied in the signals.
2. Every objection MUST cite the signal_id(s) it came from.
3. Do NOT invent objections, competitor claims, pricing, or features not in the signals.
4. Rebuttals should reference signal evidence, not made-up proof points.
5. If fewer than 3 objections can be extracted, return fewer. Do NOT pad with invented content.

Output STRICT JSON only:
{
  "objections": [
    {
      "category": "price_value|timing|complexity|risk|fit|competition|inertia",
      "objection_text": "string — as a buyer would say it, based on signal evidence",
      "frequency": "high|medium|low",
      "rebuttal": {
        "acknowledge": "string",
        "reframe": "string",
        "proof": "string — cite signal evidence only",
        "talk_track": "string"
      },
      "signal_ids": ["uuid — REQUIRED, at least one"],
      "evidence_urls": ["string — from the signal data"]
    }
  ],
  "summary": {
    "total_objections": number,
    "top_category": "string"
  }
}`;

const userContent = `Week: ${weekStart} to ${weekEnd}
${isPersonalized ? 'Company: ' + companyName : ''}

Extract objections from these signals ONLY:
${JSON.stringify(structuredSignals, null, 2)}

Do NOT add any objections not supported by the signal data above.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2500,
  temperature: 0.1,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'objection_library',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    user_id: userCtx.user_id || null,
    user_company_name: userCtx.company_name || null,
    is_personalized: isPersonalized || false,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Objection Library').first().json;

const content = anthropicResponse.content[0].text;

let objectionLibrary;
try {
  const cleaned = content.replace(/^```json?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
  objectionLibrary = JSON.parse(cleaned);
} catch (e) {
  objectionLibrary = { objections: [], summary: { total_objections: 0, top_category: 'unknown', new_this_week: 0, trending_up: [], trending_down: [] } };
}

if (!objectionLibrary.objections || !Array.isArray(objectionLibrary.objections)) {
