  signal_type: s.signal_type,
  severity: s.severity,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || []
}));

const MAX_COMPETITORS = isPersonalized ? Math.min(competitorNames.length, 5) : 3;

const systemPrompt = `You are a SIGNAL FORMATTER building competitive battlecards from intelligence signals${isPersonalized ? ` for ${companyName}` : ''}.

ABSOLUTE RULES:
1. ONLY report changes that are EXPLICITLY described in the signals provided.
2. Every change, talk track, and landmine MUST cite signal_id(s).
3. Do NOT fabricate competitor pricing, features, hires, product launches, or strategic moves.
4. Do NOT infer strategic intent beyond what signals explicitly state.
5. If a competitor has no signals this week, do NOT create a battlecard for them.
6. Talk tracks must be based on observed signal evidence, not invented competitive claims.

${isPersonalized ? `COMPANY: ${companyName}\nTRACKED COMPETITORS: ${competitorNames.join(', ')}\nOnly build battlecards for competitors that appear in the signals.` : ''}

Output STRICT JSON only:
{
  "battlecards": [
    {
      "competitor_name": "string — must match a name in the signals",
      "what_changed_this_week": [
        {
          "change": "string — factual observation from signal",
          "implication": "string — what this means based on the signal",
          "counter_move": "string — recommended response",
          "signal_ids": ["uuid — REQUIRED"],
          "evidence_urls": ["string — from signal data"]
        }
      ],
      "talk_tracks": [
        {
          "scenario": "string",
          "key_points": ["string — max 3, based on signals"],
          "signal_ids": ["uuid"]
        }
      ],
      "landmines": [
        {
          "claim_to_avoid": "string",
          "why": "string — based on signal evidence",
          "signal_ids": ["uuid"]
        }
      ]
    }
  ],
  "summary": {
    "competitors_covered": number,
    "total_changes_this_week": number
  }
}`;

const userContent = `Week: ${weekStart} to ${weekEnd}
${isPersonalized ? 'Company: ' + companyName + '\nTracked Competitors: ' + competitorNames.join(', ') : ''}

Build battlecards from these signals ONLY:
${JSON.stringify(structuredSignals, null, 2)}

Do NOT add any competitive claims not supported by the signal data above.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 3000,
  temperature: 0.1,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'battlecards',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    user_id: userCtx.user_id || null,
    user_company_name: userCtx.company_name || null,
    is_personalized: isPersonalized || false,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Battlecards').first().json;

const rawContent = anthropicResponse.content[0].text;
const cleaned = rawContent.replace(/^```json?\s*\n?/, '').replace(/^```\s*\n?/, '').replace(/\n?```\s*$/, '').trim();

let battlecardsData;
try {
  battlecardsData = JSON.parse(cleaned);
} catch (e) {
  battlecardsData = { battlecards: [], summary: { competitors_covered: 0, total_changes_this_week: 0, highest_priority_competitor: 'unknown', key_market_shifts: [] } };
}

if (!battlecardsData.battlecards || !Array.isArray(battlecardsData.battlecards)) {
  battlecardsData.battlecards = [];
}

const items = battlecardsData.battlecards.map(card => ({
  json: {
    competitor_name: card.competitor_name,
    week_start: builderData.week_start,
    week_end: builderData.week_end,
    content_md: JSON.stringify(card, null, 2),
    included_signal_ids: card.what_changed_this_week?.flatMap(c => c.signal_ids || []) || [],
    what_changed_summary: card.what_changed_this_week?.map(c => c.change).join('; ') || '',
    user_id: builderData.user_id,
    user_company_name: builderData.user_company_name,
    is_personalized: builderData.is_personalized
  }
}));

if (items.length === 0) {
  return [{ json: { _empty: true, user_id: builderData.user_id } }];
}

return items;

