=-- Insert audit trail for verified claims
{{ 
  (() => {
    const auditTrail = $('Parse Packet JSON').first().json.audit_trail || [];
    const packetId = $json.id;
    if (auditTrail.length === 0) return 'SELECT 1; -- no claims to audit';

    const values = auditTrail.map(claim => {
      const text = claim.claim_text.replace(/'/g, "''");
      const loc = claim.claim_location.replace(/'/g, "''");
      const sids = claim.signal_ids.map(s => "'" + s + "'").join(',');
      return "('" + packetId + "', '" + text + "', '" + loc + "', ARRAY[" + sids + "]::uuid[])";
    }).join(',\n');

    return 'INSERT INTO control_plane.packet_claim_sources (packet_id, claim_text, claim_location, signal_ids) VALUES\n' + values + '\nON CONFLICT DO NOTHING;';
  })()
}}
